  5	  PrometheusResponse,
  6	  useK8sWatchResource,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import PipelineRunsForRepositoriesList from './PipelineRunsForRepositoriesList';
  9	import PipelineRunsForPipelinesListK8s from './PipelineRunsForPipelinesListK8s';
 10	import SearchInputField from '../SearchInput';
 11	import { isMatchingFirstTickValue, useQueryParams } from '../utils';
 12	import { ALL_NAMESPACES_KEY } from '../../../consts';
 13	import {
 14	  usePipelineMetricsForAllNamespacePoll,
 15	  usePipelineMetricsForNamespacePoll,
 16	} from '../../pipelines-metrics/hooks';
 17	import {
 18	  MetricsQueryPrefix,
 19	  PipelineQuery,
 20	} from '../../pipelines-metrics/utils';
 21	import { getXaxisValues, secondsToHms } from '../dateTime';
 22	import { Project } from '../../../types';
 23	import { useTranslation } from 'react-i18next';
 24	
 25	type PipelineRunsListPageProps = {
 26	  bordered?: boolean;
 27	  namespace: string;
 28	  timespan: number;
 29	  interval: number;
 30	};
 31	
 32	const processData = (
 33	  countData: PrometheusResponse,
 34	  durationData: PrometheusResponse,
 35	  tickValues: number[] | Date[],
 36	  type: string,
 37	) => {
 38	  if (!countData?.data?.result || !durationData?.data?.result) {
 39	    return [];
 40	  }
 41	  const firstTickValue = tickValues[0];
 42	  const grouped: {
 43	    [key: string]: {
 44	      group_value: string;
 45	      total: number;
 46	      succeeded: number;
 47	      total_duration: number;
 48	    };
 49	  } = {};
 50	
 51	  countData?.data?.result?.forEach((item) => {
 52	    const { namespace, pipeline, status } = item.metric;
 53	    if (pipeline === 'anonymous' || !pipeline) return;
 54	
 55	    const key = `${namespace}/${pipeline}`;
 56	    const lastTimestamp = item.values[item.values.length - 1][0];
 57	    const lastValue = parseInt(item.values[item.values.length - 1][1], 10);
 58	
 59	    const isMatch = isMatchingFirstTickValue(
 60	      firstTickValue,
 61	      lastTimestamp,
 62	      type,
 63	    );
 64	    if (isMatch) return;
 65	
 66	    if (!grouped[key]) {
 67	      grouped[key] = {
 68	        group_value: key,
 69	        total: 0,
 70	        succeeded: 0,
 71	        total_duration: 0,
 72	      };
 73	    }
 74	
 75	    grouped[key].total += lastValue;
 76	
 77	    if (status === 'success') {
 78	      grouped[key].succeeded += lastValue;
 79	    }
 80	  });
 81	
 82	  durationData?.data?.result?.forEach((item) => {
 83	    const { namespace, pipeline } = item.metric;
 84	    if (pipeline === 'anonymous' || !pipeline) return;
 85	
 86	    const key = `${namespace}/${pipeline}`;
 87	    const lastTimestamp = item.values[item.values.length - 1][0];
 88	    const lastDuration = parseFloat(item.values[item.values.length - 1][1]);
 89	
 90	    const isMatch = isMatchingFirstTickValue(
 91	      firstTickValue,
 92	      lastTimestamp,
 93	      type,
 94	    );
 95	    if (isMatch) return;
 96	
 97	    if (!grouped[key]) {
 98	      grouped[key] = {
 99	        group_value: key,
100	        total: 0,
101	        succeeded: 0,
102	        total_duration: 0,
103	      };
104	    }
105	
106	    grouped[key].total_duration += lastDuration;
107	  });
108	
109	  return Object.values(grouped).map((group) => {
110	    const avgDuration =
111	      group.total > 0 ? group.total_duration / group.total : 0;
112	    return {
113	      ...group,
114	      total_duration: secondsToHms(group.total_duration),
115	      avg_duration: secondsToHms(avgDuration),
116	    };
117	  });
118	};
