120	const PipelineRunsListPageK8s: React.FC<PipelineRunsListPageProps> = ({
121	  bordered,
122	  namespace,
123	  timespan,
124	  interval,
125	}) => {
126	  const [pageFlag, setPageFlag] = React.useState(1);
127	  const [searchText, setSearchText] = React.useState('');
128	  const [tickValues, type] = getXaxisValues(timespan);
129	  const { t } = useTranslation('plugin__pipelines-console-plugin');
130	
131	  const [projects, projectsLoaded] = useK8sWatchResource<Project[]>({
132	    isList: true,
133	    kind: 'Project',
134	    optional: true,
135	  });
136	  const [pipelineRunsListError, setPipelineRunsListError] = React.useState<
137	    string | null
138	  >(null);
139	  const [
140	    pipelineRunsMetricsCountData,
141	    pipelineRunsMetricsCountError,
142	    loadingPipelineRunsMetricsCount,
143	  ] =
144	    namespace == ALL_NAMESPACES_KEY
145	      ? usePipelineMetricsForAllNamespacePoll({
146	          timespan,
147	          delay: interval,
148	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
149	          metricsQuery:
150	            PipelineQuery.PIPELINERUN_COUNT_WITH_METRIC_FOR_ALL_NAMESPACE,
151	          timeout: 90000,
152	        })
153	      : usePipelineMetricsForNamespacePoll({
154	          namespace,
155	          timespan,
156	          delay: interval,
157	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
158	          metricsQuery:
159	            PipelineQuery.PIPELINERUN_COUNT_WITH_METRIC_FOR_NAMESPACE,
160	          timeout: 90000,
161	        });
162	
163	  const [
164	    pipelineRunsMetricsSumData,
165	    pipelineRunsMetricsSumError,
166	    loadingPipelineRunsMetricsSum,
167	  ] =
168	    namespace == ALL_NAMESPACES_KEY
169	      ? usePipelineMetricsForAllNamespacePoll({
170	          timespan,
171	          delay: interval,
172	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
173	          metricsQuery:
174	            PipelineQuery.PIPELINERUN_SUM_WITH_METRIC_FOR_ALL_NAMESPACE,
175	          timeout: 90000,
176	        })
177	      : usePipelineMetricsForNamespacePoll({
178	          namespace,
179	          timespan,
180	          delay: interval,
181	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
182	          metricsQuery: PipelineQuery.PIPELINERUN_SUM_WITH_METRIC_FOR_NAMESPACE,
183	          timeout: 90000,
184	        });
185	
186	  const summaryDataK8s = React.useMemo(() => {
187	    if (pipelineRunsMetricsCountError || pipelineRunsMetricsSumError) {
188	      return [];
189	    }
190	    return processData(
191	      pipelineRunsMetricsCountData,
192	      pipelineRunsMetricsSumData,
193	      tickValues,
194	      type,
195	    );
196	  }, [
197	    pipelineRunsMetricsCountData,
198	    pipelineRunsMetricsSumData,
199	    pipelineRunsMetricsCountError,
200	    pipelineRunsMetricsSumError,
201	    tickValues,
202	    type,
203	  ]);
204	
205	  const summaryDataFiltered = React.useMemo(() => {
206	    return summaryDataK8s.filter((summary) =>
207	      summary.group_value
208	        .split('/')[1]
209	        .toLowerCase()
210	        .includes(searchText.toLowerCase()),
211	    );
212	  }, [searchText, summaryDataK8s]);
213	
214	  useQueryParams({
215	    key: 'search',
216	    value: searchText,
217	    setValue: setSearchText,
218	    defaultValue: '',
219	  });
220	
221	  useQueryParams({
222	    key: 'list',
223	    value: pageFlag,
224	    setValue: setPageFlag,
225	    defaultValue: 1,
226	    options: { perpipeline: 1, perrepository: 2 },
227	    displayFormat: (v) => (v == 1 ? 'perpipeline' : 'perrepository'),
228	    loadFormat: (v) => (v == 'perrepository' ? 2 : 1),
229	  });
230	
231	  // const handlePageChange = (pageNumber: number) => {
232	  //   setloaded(false);
233	  //   setSummaryData([]);
234	  //   setSummaryDataFiltered([]);
235	  //   setPageFlag(pageNumber);
236	  // };
237	  const handleNameChange = (value: string) => {
238	    setSearchText(value);
239	  };
240	
241	  React.useEffect(() => {
242	    const hasNonAbortError =
243	      (pipelineRunsMetricsCountError &&
244	        pipelineRunsMetricsCountError.name !== 'AbortError') ||
245	      (pipelineRunsMetricsSumError &&
246	        pipelineRunsMetricsSumError.name !== 'AbortError');
247	
248	    setPipelineRunsListError(
249	      hasNonAbortError
