251	            pipelineRunsMetricsCountError?.message ??
252	            t('Unable to load pipeline runs')
253	        : null,
254	    );
255	  }, [pipelineRunsMetricsCountError, pipelineRunsMetricsSumError, t]);
256	
257	  return (
258	    <Card
259	      className={classNames('pipeline-overview__pipelinerun-status-card', {
260	        'card-border': bordered,
261	      })}
262	    >
263	      <CardBody>
264	        {pipelineRunsListError ? (
265	          <Alert
266	            variant="danger"
267	            isInline
268	            title={t('Unable to load pipeline runs list')}
269	            className="pf-v6-u-mb-md"
270	          />
271	        ) : (
272	          <>
273	            <Grid hasGutter className="pipeline-overview__listpage__grid">
274	              <GridItem
275	                span={9}
276	                className="pipeline-overview__listpage__griditem"
277	              >
278	                {/* Lastrun Status is not provided by API  */}
279	                {/* <StatusDropdown /> */}
280	                <SearchInputField
281	                  searchText={searchText}
282	                  pageFlag={pageFlag}
283	                  handleNameChange={handleNameChange}
284	                />
285	              </GridItem>
286	              {/*
287	          Since Pipeline metrics for PAC is not available, commenting this
288	          <GridItem span={3}>
289	            <ToggleGroup className="pipeline-overview__listpage__button">
290	              <ToggleGroupItem
291	                text={t('Per Pipeline')}
292	                buttonId="pipelineButton"
293	                isSelected={pageFlag === 1}
294	                onChange={() => handlePageChange(1)}
295	              />
296	              <ToggleGroupItem
297	                text={t('Per Repository')}
298	                buttonId="repositoryButton"
299	                isSelected={pageFlag === 2}
300	                onChange={() => handlePageChange(2)}
301	              />
302	            </ToggleGroup>
303	          </GridItem> */}
304	            </Grid>
305	            <Grid hasGutter>
306	              <GridItem span={12}>
307	                {pageFlag === 1 ? (
308	                  <PipelineRunsForPipelinesListK8s
309	                    summaryData={summaryDataK8s}
310	                    summaryDataFiltered={summaryDataFiltered}
311	                    loaded={
312	                      !loadingPipelineRunsMetricsCount &&
313	                      !loadingPipelineRunsMetricsSum
314	                    }
315	                    hideLastRunTime={true}
316	                    projects={projects}
317	                    projectsLoaded={projectsLoaded}
318	                  />
319	                ) : (
320	                  <PipelineRunsForRepositoriesList
321	                    summaryData={summaryDataK8s}
322	                    summaryDataFiltered={summaryDataFiltered}
323	                    loaded={
324	                      !loadingPipelineRunsMetricsCount &&
325	                      !loadingPipelineRunsMetricsSum
326	                    }
327	                  />
328	                )}
329	              </GridItem>
330	            </Grid>
331	          </>
332	        )}
333	      </CardBody>
334	    </Card>
335	  );
336	};
337	
338	export default PipelineRunsListPageK8s;

